theme_moove.scss:
/* Ocultar "made by" del footer */
.madeby {
    display: none;
}

/* Navegacion secundaria */
.secondary-navigation,
.secondary-navigation .moremenu,
.secondary-navigation .nav-tabs {
    background-color: #4472c4 !important;
    border: 0 !important;
}

.secondary-navigation .nav-tabs .nav-link {
    color: #ffffff !important;
}

.secondary-navigation .nav-tabs .nav-link:hover,
.secondary-navigation .nav-tabs .nav-link.active {
    color: #ffffff !important;
    background-color: #4472c4 !important;
    text-decoration: none;
}

.secondary-navigation .moremenu .nav-tabs .nav-link {
    color: #000000;
}

.secondary-navigation .moremenu .nav-tabs .nav-link:hover {
    color: #FFFFFF;
}

/* Banner de cookies */
.cc-window {
    background-color: #4472c4 !important;
    color: #ffffff !important;
}

.cc-window a {
    color: #ffffff !important;
    text-decoration: underline;
}

.cc-btn {
    background-color: #000000 !important;
    color: #ffffff !important;
    border-radius: 4px;
}

.cc-btn:hover {
    background-color: #e6e6e6 !important;
}

.custom-footer-links {
  padding-top: 10px;
  text-align: center;

  a {
    display: block;
    color: #ffffff;
    padding: 5px 0;
    text-decoration: none;

    &:hover {
      text-decoration: underline;
    }
  }
}

#page-footer::after {
    content: "CONTACTO: 943 11 3540 / 2327 / 2350 - prestakuntza@gipuzkoa.eus";
    display: block;
    text-align: right;
    color: #ffffff;
    font-size: 14px;
    margin-top: 10px;
    padding-right: 20px;
}

